import React, { useState, useEffect } from 'react';
import axios from 'axios';
import './AppointmentList.css';

const AppointmentList = () => {
  const [appointments, setAppointments] = useState([]);
  const [doctors, setDoctors] = useState({});
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [filter, setFilter] = useState('all');

  useEffect(() => {
    fetchAppointments();
    fetchDoctors();
  }, []);

  const fetchAppointments = async () => {
    try {
      const response = await axios.get('http://localhost:5000/api/appointments');
      setAppointments(response.data);
      setLoading(false);
    } catch (error) {
      setError('Error fetching appointments');
      setLoading(false);
    }
  };

  const fetchDoctors = async () => {
    try {
      const response = await axios.get('http://localhost:5000/api/doctors');
      const doctorsMap = {};
      response.data.forEach(doctor => {
        doctorsMap[doctor._id] = doctor;
      });
      setDoctors(doctorsMap);
    } catch (error) {
      console.error('Error fetching doctors:', error);
    }
  };

  const updateStatus = async (id, newStatus) => {
    try {
      await axios.patch(`http://localhost:5000/api/appointments/${id}`, {
        status: newStatus
      });
      fetchAppointments();
    } catch (error) {
      console.error('Error updating appointment:', error);
    }
  };

  const deleteAppointment = async (id) => {
    if (window.confirm('Are you sure you want to delete this appointment?')) {
      try {
        await axios.delete(`http://localhost:5000/api/appointments/${id}`);
        fetchAppointments();
      } catch (error) {
        console.error('Error deleting appointment:', error);
      }
    }
  };

  const getStatusColor = (status) => {
    const colors = {
      pending: '#ffc107',
      confirmed: '#28a745',
      cancelled: '#dc3545',
      completed: '#17a2b8'
    };
    return colors[status] || '#6c757d';
  };

  const filteredAppointments = appointments.filter(appointment => {
    if (filter === 'all') return true;
    return appointment.status === filter;
  });

  if (loading) return <div className="loading">Loading...</div>;
  if (error) return <div className="error">{error}</div>;

  return (
    <div className="appointment-list">
      <h2>Appointments</h2>

      <div className="filters">
        <button 
          className={filter === 'all' ? 'active' : ''} 
          onClick={() => setFilter('all')}
        >
          All
        </button>
        <button 
          className={filter === 'pending' ? 'active' : ''} 
          onClick={() => setFilter('pending')}
        >
          Pending
        </button>
        <button 
          className={filter === 'confirmed' ? 'active' : ''} 
          onClick={() => setFilter('confirmed')}
        >
          Confirmed
        </button>
        <button 
          className={filter === 'completed' ? 'active' : ''} 
          onClick={() => setFilter('completed')}
        >
          Completed
        </button>
        <button 
          className={filter === 'cancelled' ? 'active' : ''} 
          onClick={() => setFilter('cancelled')}
        >
          Cancelled
        </button>
      </div>

      <div className="appointments-container">
        {filteredAppointments.map((appointment) => (
          <div key={appointment._id} className="appointment-card">
            <div className="appointment-header">
              <h3>{appointment.patientName}</h3>
              <span 
                className="status-badge"
                style={{ backgroundColor: getStatusColor(appointment.status) }}
              >
                {appointment.status}
              </span>
            </div>

            <div className="appointment-info">
              <div className="info-section">
                <h4>Patient Information</h4>
                <p><strong>Age:</strong> {appointment.age}</p>
                <p><strong>Gender:</strong> {appointment.gender}</p>
                <p><strong>Email:</strong> {appointment.email}</p>
                <p><strong>Phone:</strong> {appointment.phone}</p>
              </div>

              <div className="info-section">
                <h4>Doctor Information</h4>
                {doctors[appointment.doctor] && (
                  <>
                    <p><strong>Doctor:</strong> Dr. {doctors[appointment.doctor].name}</p>
                    <p><strong>Specialization:</strong> {doctors[appointment.doctor].specialization}</p>
                    <p><strong>Consultation Fee:</strong> ${doctors[appointment.doctor].consultationFee}</p>
                  </>
                )}
              </div>

              <div className="info-section">
                <h4>Appointment Details</h4>
                <p><strong>Date:</strong> {new Date(appointment.appointmentDate).toLocaleDateString()}</p>
                <p><strong>Time:</strong> {appointment.appointmentTime}</p>
                <p><strong>Reason:</strong> {appointment.reason}</p>
                <p><strong>Symptoms:</strong> {appointment.symptoms}</p>
                {appointment.previousMedicalHistory && (
                  <p><strong>Medical History:</strong> {appointment.previousMedicalHistory}</p>
                )}
              </div>
            </div>

            <div className="appointment-actions">
              <select
                value={appointment.status}
                onChange={(e) => updateStatus(appointment._id, e.target.value)}
                style={{ backgroundColor: getStatusColor(appointment.status) }}
              >
                <option value="pending">Pending</option>
                <option value="confirmed">Confirmed</option>
                <option value="completed">Completed</option>
                <option value="cancelled">Cancelled</option>
              </select>
              <button
                className="delete-btn"
                onClick={() => deleteAppointment(appointment._id)}
              >
                Delete
              </button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default AppointmentList;
